using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ── DI & services ──────────────────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ── Tools ──────────────────────────────────────────────────────────────────────
var notebook = new ResearchNotebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) =>
        {
            return WebSearchTool.SearchAsync(query);
        },
        new AIFunctionFactoryOptions
        {
            Name = "web_search",
            Description = "Searches the web for information on a topic and returns a list of result snippets.",
        }),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\"";
        },
        new AIFunctionFactoryOptions
        {
            Name = "save_note",
            Description = "Saves a research note with a title and content for later summarization.",
        }),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        new AIFunctionFactoryOptions
        {
            Name = "get_notes",
            Description = "Retrieves all saved research notes.",
        }),
};

// ── Agent ──────────────────────────────────────────────────────────────────────
const string instructions = """
    You are a research assistant. When given a topic:
    1. Use the web_search tool multiple times to find diverse, relevant information.
    2. Use save_note to record key findings as you go — give each note a descriptive title.
    3. After gathering enough information, use get_notes to review everything you collected.
    4. Produce a well-structured summary with sections, citing the sources you found.
    Be thorough but concise. Aim for 3-5 searches and 3-5 notes before summarizing.
    """;

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        Instructions = instructions,
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    },
    loggerFactory);

// ── Run ────────────────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    topic, session, cancellationToken: CancellationToken.None))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine("\n\n── Research complete ──");
Console.WriteLine($"Notes collected: {notebook.Count}");

// ── Helpers ────────────────────────────────────────────────────────────────────
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(topic)
        ? "Recent advances in quantum computing"
        : topic;
}

// ════════════════════════════════════════════════════════════════════════════════
//  Web Search Tool — uses Bing search via scraping for demonstration purposes.
//  In production, replace with a proper search API (Bing Search API, Google, etc.)
// ════════════════════════════════════════════════════════════════════════════════
static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await s_http.GetStringAsync(url);

            var results = ParseSearchResults(html);

            if (results.Count == 0)
            {
                return $"No results found for \"{query}\".";
            }

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":");
            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"- **{title}**: {snippet} ({link})");
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Link)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Parse DuckDuckGo HTML results
        var resultBlocks = html.Split(["class=\"result__body\""], StringSplitOptions.None);

        foreach (var block in resultBlocks.Skip(1).Take(5))
        {
            var title = ExtractBetween(block, "class=\"result__a\"", "</a>")
                ?? "Untitled";
            // Clean HTML tags from title
            title = StripHtml(title);

            var snippet = ExtractBetween(block, "class=\"result__snippet\"", "</td>")
                ?? ExtractBetween(block, "class=\"result__snippet\"", "</span>")
                ?? "";
            snippet = StripHtml(snippet);

            var link = ExtractHref(block, "class=\"result__url\"")
                ?? ExtractHref(block, "class=\"result__a\"")
                ?? "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add((title.Trim(), snippet.Trim(), link.Trim()));
            }
        }

        return results;
    }

    private static string? ExtractBetween(string text, string startMarker, string endMarker)
    {
        var start = text.IndexOf(startMarker, StringComparison.Ordinal);
        if (start < 0) return null;

        // Move past the closing > of the tag
        var contentStart = text.IndexOf('>', start + startMarker.Length);
        if (contentStart < 0) return null;
        contentStart++;

        var end = text.IndexOf(endMarker, contentStart, StringComparison.Ordinal);
        if (end < 0) return null;

        return text[contentStart..end];
    }

    private static string? ExtractHref(string text, string nearMarker)
    {
        var markerPos = text.IndexOf(nearMarker, StringComparison.Ordinal);
        if (markerPos < 0) return null;

        // Search backward for href
        var searchRegion = text[Math.Max(0, markerPos - 500)..markerPos];
        var hrefPos = searchRegion.LastIndexOf("href=\"", StringComparison.Ordinal);
        if (hrefPos < 0)
        {
            // Search forward
            var fwd = text.IndexOf("href=\"", markerPos, StringComparison.Ordinal);
            if (fwd < 0 || fwd > markerPos + 500) return null;
            var fwdStart = fwd + 6;
            var fwdEnd = text.IndexOf('"', fwdStart);
            return fwdEnd > fwdStart ? text[fwdStart..fwdEnd] : null;
        }

        var start = hrefPos + 6;
        var end = searchRegion.IndexOf('"', start);
        return end > start ? searchRegion[start..end] : null;
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder(html.Length);
        var inTag = false;
        foreach (var c in html)
        {
            if (c == '<') { inTag = true; continue; }
            if (c == '>') { inTag = false; continue; }
            if (!inTag) sb.Append(c);
        }

        return System.Net.WebUtility.HtmlDecode(sb.ToString());
    }
}

// ════════════════════════════════════════════════════════════════════════════════
//  Research Notebook — in-memory note storage
// ════════════════════════════════════════════════════════════════════════════════
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime CreatedAt)> _notes = [];

    public int Count => _notes.Count;

    public void AddNote(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
    }

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Research Notes ({_notes.Count} total):");
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content, createdAt) = _notes[i];
            sb.AppendLine($"\n--- Note {i + 1}: {title} (saved {createdAt:HH:mm:ss}) ---");
            sb.AppendLine(content);
        }

        return sb.ToString();
    }
}

